      article.id === id ? { ...article, quantite: article.quantite + 1 } : article
    )
  );
};
```

```javascript
const modifierNote = () => {
  setEtudiants(prevEtudiants =>
    prevEtudiants.map(etudiant =>
      etudiant.id === 2
        ? { ...etudiant, notes: { ...etudiant.notes, maths: 19 } }
        : etudiant
    )
  );
};
```

```javascript
import { produce } from 'immer';

const modifierNoteAvecImmer = () => {
  setEtudiants(produce(draft => {
    const etudiant = draft.find(e => e.id === 2);
    if (etudiant) {
      etudiant.notes.maths = 19;
    }
  }));
};
```

questions.texte:
Identifier l'erreur probable dans le code suivant et proposer une correction :
```javascript
const ajouterProduit = (nouveauProduit) => {
  panier.produits.push(nouveauProduit);
  setPanier(panier);
};
```

Corriger la fonction `modifierQuantite(id, nouvelleQuantite)` qui actuellement met à jour tous les produits :
```javascript
const modifierQuantite = (id, nouvelleQuantite) => {
  panier.produits.forEach(p => p.quantite = nouvelleQuantite);
  setPanier(panier);
};
```

questions.reponse:
Le code modifie directement tous les produits au lieu du produit ciblé. Correction :
```javascript
const modifierQuantite = (id, nouvelleQuantite) => {
  setPanier(prevPanier => ({
    ...prevPanier,
    produits: prevPanier.produits.map(p =>
      p.id === id ? { ...p, quantite: nouvelleQuantite } : p
    )
  }));
};
```

Le calcul du total ne modifie pas l'état, donc l'immutabilité n'est pas une contrainte. On utilise simplement `reduce` :
```javascript
const calculerTotal = (panier) => {
  return panier.produits.reduce((total, p) => total + (p.prix * p.quantite), 0);
};
```
Pour que le total se mette à jour automatiquement, on peut le calculer directement dans le rendu ou utiliser `useMemo` pour optimiser.
